preDeployCommands:
cat > "{{STACK_DIR}}/prestashop-post-install.sh" <<'EOF'
#!/bin/sh
set -eu

echo '[post-install] Patching PrestaShop settings (shop URL + SSL flags)'

php <<'PHP'
<?php
$host = getenv('DB_SERVER') ?: 'db';
$db = getenv('DB_NAME') ?: 'prestashop';
$user = getenv('DB_USER') ?: 'prestashop';
$pass = getenv('DB_PASSWD') ?: '';
$prefix = getenv('DB_PREFIX') ?: 'ps_';
$domain = getenv('PS_DOMAIN') ?: '';
$domain = preg_replace('#^https?://#', '', $domain);
$domain = rtrim($domain, '/');

$dsn = sprintf('mysql:host=%s;dbname=%s;charset=utf8', $host, $db);
$attempts = 30;
while (true) {
  try {
    $pdo = new PDO($dsn, $user, $pass, [PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION]);
    break;
  } catch (Exception $e) {
    $attempts--;
    if ($attempts <= 0) {
      fwrite(STDERR, "[post-install] DB connection failed: " . $e->getMessage() . "\n");
      exit(1);
    }
    sleep(2);
  }
}

$cfg = $prefix . 'configuration';
$shopUrl = $prefix . 'shop_url';

$pdo->exec("UPDATE `$cfg` SET `value`='0' WHERE `name` IN ('PS_SSL_ENABLED','PS_SSL_ENABLED_EVERYWHERE')");

if ($domain !== '') {
  $stmt = $pdo->prepare("UPDATE `$cfg` SET `value`=:d WHERE `name` IN ('PS_SHOP_DOMAIN','PS_SHOP_DOMAIN_SSL')");
  $stmt->execute([':d' => $domain]);

  $stmt = $pdo->prepare("UPDATE `$shopUrl` SET `domain`=:d, `domain_ssl`=:d, `physical_uri`='/', `virtual_uri`='' WHERE `main`=1");
  $stmt->execute([':d' => $domain]);
}
PHP

rm -rf /var/www/html/var/cache/* || true

echo '[post-install] Done'
EOF

templates.postDeploymentSteps:
1. Wait for auto-install to complete (~1-2 min, check: docker compose logs -f prestashop)
2. Visit store: http://YOUR_SERVER_IP:{{PORT}}
3. Admin panel: http://YOUR_SERVER_IP:{{PORT}}/{{PS_FOLDER_ADMIN}}
4. To enable HTTPS later: Admin > Shop Parameters > General > Enable SSL

templates.compose:
services:
  web:
    image: nginx:alpine
    ports:
      - "{{PORT}}:80"
    volumes:
      - invoiceninja_public:/var/www/app/public:ro
      - invoiceninja_storage:/var/www/app/storage:ro
    depends_on:
      - invoiceninja
    command: |
      /bin/sh -c "cat > /etc/nginx/conf.d/default.conf <<'EOF'
      server {
        listen 80;
        server_name _;
        root /var/www/app/public;
        index index.php index.html;
        client_max_body_size 100m;

        location / {
          try_files $$uri $$uri/ /index.php?$$query_string;
        }

        location ~ \.php$$ {
          try_files $$uri =404;
          fastcgi_split_path_info ^(.+\.php)(/.+)$$;
          fastcgi_pass invoiceninja:9000;
          fastcgi_index index.php;
          include fastcgi_params;
          fastcgi_param SCRIPT_FILENAME $$document_root$$fastcgi_script_name;
          fastcgi_param PATH_INFO $$fastcgi_path_info;
        }

        location ~ /\. {
          deny all;
        }
      }
      EOF
      nginx -g 'daemon off;'"
    restart: unless-stopped

  invoiceninja:
    image: invoiceninja/invoiceninja-debian:latest
    environment:
      - APP_URL={{APP_URL}}
      - APP_KEY={{APP_KEY}}
      - APP_ENV=production
      - APP_DEBUG=false
      - IN_USER_EMAIL={{IN_USER_EMAIL}}
      - IN_PASSWORD={{IN_PASSWORD}}
      - DB_HOST=db
      - DB_DATABASE=ninja
      - DB_USERNAME=ninja
      - DB_PASSWORD={{DB_PASSWORD}}
      - REQUIRE_HTTPS=false
    volumes:
      - invoiceninja_public:/var/www/app/public
      - invoiceninja_storage:/var/www/app/storage
    restart: unless-stopped
    depends_on:
      db:
        condition: service_healthy

  db:
    image: mysql:8.0
    environment:
      - MYSQL_ROOT_PASSWORD={{DB_ROOT_PASSWORD}}
      - MYSQL_DATABASE=ninja
      - MYSQL_USER=ninja
      - MYSQL_PASSWORD={{DB_PASSWORD}}
    volumes:
      - mysql_data:/var/lib/mysql
    restart: unless-stopped
    healthcheck:
      test: ["CMD-SHELL", "mysqladmin ping -h localhost -u root -p$$MYSQL_ROOT_PASSWORD || exit 1"]
      interval: 10s
      timeout: 5s
      retries: 5
      start_period: 30s

volumes:
  invoiceninja_public:
  invoiceninja_storage:
  mysql_data:
